{%- set existing_groups = dashboard["dashboard_groups"] -%}
{%- set d_pages = [] -%}
{%- set d_groups = [] -%}

{# Step 1: Load original dlist #}
{%- set dlist = engine.query_stream_data(stream="rda_packs_dynamic_groups_and_pages", cfxql_query="customer_tag is empty") or [] -%}

{# Helper: Convert version string to list of integers #}
{%- macro version_to_list(version) -%}
    {%- set parts = [] -%}
    {%- set current = "" -%}
    {%- for c in version ~ "." -%}
        {%- if c == "." -%}
            {%- if current != "" -%}
                {%- set _ = parts.append(current|int) -%}
            {%- else -%}
                {%- set _ = parts.append(0) -%}
            {%- endif -%}
            {%- set current = "" -%}
        {%- else -%}
            {%- set current = current + c -%}
        {%- endif -%}
    {%- endfor -%}
    {{ parts }}
{%- endmacro -%}

{# Helper: pad version list to desired length #}
{%- macro pad_version_list(vlist, max_len) -%}
    {%- set padded = vlist[:] -%}
    {%- for i in range(max_len - (vlist|length)) -%}
        {%- set _ = padded.append(0) -%}
    {%- endfor -%}
    {{ padded }}
{%- endmacro -%}

{# Group dlist by pack_id #}
{%- set grouped = {} -%}
{%- for row in dlist -%}
    {%- set pid = row.pack_id -%}
    {%- if pid not in grouped -%}
        {%- set _ = grouped.update({pid: [row]}) -%}
    {%- else -%}
        {%- set _ = grouped[pid].append(row) -%}
    {%- endif -%}
{%- endfor -%}

{%- set filtered_dlist = [] -%}

{%- for pid, rows in grouped.items() -%}

    {# If only one row exists for this pack_id, include it #}
    {%- if rows|length == 1 -%}
        {%- set _ = filtered_dlist.append(rows[0]) -%}
    {%- else -%}

        {# Step 1: Build raw version lists #}
        {%- set version_lists = [] -%}
        {%- for r in rows -%}
            {%- set v = version_to_list(r.pack_version) -%}
            {%- set _ = version_lists.append(v) -%}
        {%- endfor -%}

        {# Step 2: Find max length of version segments #}
        {%- set max_len = 0 -%}
        {%- for v in version_lists -%}
            {%- if v|length > max_len -%}
                {%- set max_len = v|length -%}
            {%- endif -%}
        {%- endfor -%}

        {# Step 3: Pad all versions #}
        {%- set padded_versions = [] -%}
        {%- for v in version_lists -%}
            {%- set pv = pad_version_list(v, max_len) -%}
            {%- set _ = padded_versions.append(pv) -%}
        {%- endfor -%}

        {# Step 4: Find max version  #}
        {%- set max_version = padded_versions[0] -%}
        {%- for pv in padded_versions -%}
            {%- if pv > max_version -%}
                {%- set max_version = pv -%}
            {%- endif -%}
        {%- endfor -%}

        {# Step 5: Append rows matching latest version #}
        {%- for idx in range(padded_versions|length) -%}
            {%- if padded_versions[idx] == max_version -%}
                {%- set _ = filtered_dlist.append(rows[idx]) -%}
            {%- endif -%}
        {%- endfor -%}
    {%- endif -%}

{%- endfor -%}

{# Replace original dlist with filtered version #}
{%- set dlist = filtered_dlist -%}


{# =============================== #}
{# Continue with your existing logic #}
{# =============================== #}

{%- if dlist -%}
   {# Filter the pages list into a new variable #}
    {%- set filtered_pages = dashboard["dashboard_pages"]
        | rejectattr("name", "equalto", "solution_base_pack_ops_overview_page")
        | list -%}

    {# Clear and repopulate dashboard_pages #}
    {%- set _ = dashboard["dashboard_pages"].clear() -%}
    {%- for p in filtered_pages -%}
        {%- set _ = dashboard["dashboard_pages"].append(p) -%}
    {%- endfor -%}

    {# Process the dlist to populate dashboard groups and pages #}
    {%- for i in dlist -%}
        {%- set page_name = i["dashboard_page_name"] -%}

        {# Skip certain known pages and those starting with 'multi' #}
        {%- if page_name != "device_SNMP_Traps_from_alerts_fault"
              and page_name != "device_syslog_from_alert_fault"
              and page_name != "device_alerts_from_alert_fault"
           and page_name != "device_incidents_from_alerts"
           and not page_name.startswith("multi") -%}

            {%- set dgroup_ = {
                "g_name": i["dashboard_group_name"],
                "g_label": i["dashboard_group_label"],
                "g_icon": i["dashboard_group_icon"]
            } -%}
            {{ d_groups.append(dgroup_) }}

            {%- set dpage_ = {
                "name": i["dashboard_page_name"],
                "label": i["dashboard_page_label"],
                "icon": i["dashboard_page_icon"],
                "group": i["dashboard_page_group"]
            } -%}
            {{ d_pages.append(dpage_) }}

        {%- endif -%}
    {%- endfor -%}

    {# Update dashboard groups #}
    {%- for group in d_groups -%}
        {%- if group.g_name not in existing_groups | map(attribute='g_name') | list -%}
            {%- set _ = dashboard["dashboard_groups"].update({
                group.g_name: {
                    "icon": group.g_icon,
                    "label": group.g_label
                }
            }) -%}
        {%- endif -%}
    {%- endfor -%}

    {# Update dashboard pages #}
    {%- for page in d_pages -%}
        {%- set _ = dashboard["dashboard_pages"].append({
            "name": page.name,
            "label": page.label,
            "icon": page.icon,
            "group": page.group
        }) -%}
    {%- endfor -%}

{%- endif -%}
